-- Plantillas de notificaciones para el módulo de ofertas laborales y candidaturas
	 -- Oferta laboral - Notificación - Cierre vencido y estado no cerrado
	('d3c1d5b7-f8d2-4df4-9f6b-2c63aa6b8e41', NOW(), NOW(), '1', '1', NULL, 'Ejemplo - Notificación - Oferta con cierre vencido sin estado cerrada', 'Plantilla para notificar al responsable que la oferta tiene cierre de candidaturas a ayer y no está en estado cerrada o similar.', 'Revisar oferta laboral: cierre de candidaturas vencido - $stic_job_offers_name', 'Estimado/a $stic_job_offers_assigned_user_name,\r\n\r\nLa oferta laboral $stic_job_offers_name tiene la fecha de cierre de candidaturas vencida (ayer) y actualmente está en estado $stic_job_offers_status.\r\n\r\nPor favor, revisa la oferta y actualiza su estado si corresponde: $sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id', '<p>Estimado/a $stic_job_offers_assigned_user_name,</p>\n<p>La oferta laboral <strong>$stic_job_offers_name</strong> tiene la fecha de cierre de candidaturas vencida (ayer) y actualmente está en estado <strong>$stic_job_offers_status</strong>.</p>\n<p>Por favor, <a href="$sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id">revisa la oferta</a> y actualiza su estado si corresponde.</p>', 0, '1', 0, 'notification'),
	-- Candidatura Aceptada - Usuario asignado 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0001', NOW(), NOW(), '1', '1', NULL, 'Ejemplo - Candidatura aceptada - Usuario asignado ', 'Notifica al usuario asignado cuando una candidatura pasa a Aceptada, con enlace al CRM.', 'Candidatura aceptada: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Estimado/a $stic_job_applications_assigned_user_name,\r\n\r\nLa candidatura de $stic_job_applications_stic_job_applications_contacts_name para la oferta $stic_job_applications_stic_job_applications_stic_job_offers_name ha cambiado a estado Aceptada.\r\n\r\nPuedes revisarla en el CRM: $sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id', '<p>Estimado/a $stic_job_applications_assigned_user_name,</p><p>La candidatura de <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> para la oferta <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> ha cambiado a estado <strong>Aceptada</strong>.</p><p>Puedes revisarla en el CRM: <a href="$sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id">Abrir candidatura en CRM</a>.</p>', 0, '1', 0, 'notification'),
	-- Candidatura Aceptada - Candidato 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0002', NOW(), NOW(), '1', '1', NULL, 'Ejemplo - Candidatura aceptada - Candidato ', 'Notifica al candidato cuando su candidatura pasa a Aceptada, con enlace al área privada.', 'Tu candidatura ha sido aceptada: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Estimado/a $stic_job_applications_stic_job_applications_contacts_name:\r\n\r\nNos complace informarte de que tu candidatura para la oferta $stic_job_applications_stic_job_applications_stic_job_offers_name ha pasado a estado Aceptada.\r\n\r\nPuedes consultar el detalle en tu área privada: $portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id', '<p>Estimado/a $stic_job_applications_stic_job_applications_contacts_name:</p><p>Nos complace informarte de que tu candidatura para la oferta <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> ha pasado a estado <strong>Aceptada</strong>.</p><p>Puedes consultar el detalle en tu área privada: <a href="$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id">Acceder al área privada</a>.</p>', 0, '1', 0, 'notification'),
	-- Candidatura Rechazada o cerrada - Usuario asignado 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0004', NOW(), NOW(), '1', '1', NULL, 'Ejemplo - Candidatura rechazada/cerrada - Usuario asignado', 'Notifica al usuario asignado el descarte.', 'Candidatura rechazada o cerrada: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Estimado/a $stic_job_applications_assigned_user_name,\n\nTe informamos de que se ha actualizado el estado de la candidatura de $stic_job_applications_stic_job_applications_contacts_name para la posición $stic_job_applications_stic_job_applications_stic_job_offers_name.\n\nEl nuevo estado es: Candidatura descartada / Proceso cerrado.\n\nPuedes revisar el detalle en el CRM: $sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id', '<p>Estimado/a <strong>$stic_job_applications_assigned_user_name</strong>,</p><p>Te informamos de que se ha actualizado el estado de la candidatura de <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> para la posición <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong>.</p><p>El nuevo estado es: <strong>Candidatura descartada / Proceso cerrado.</strong></p><p>Puedes revisar el detalle en el CRM: <a href=\"$sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id\">Abrir candidatura en CRM</a>.</p>', 0, '1', 0, 'notification'),
	-- Candidatura Rechazada o cerrada - Candidato 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0005', NOW(), NOW(), '1', '1', NULL, 'Ejemplo - Candidatura rechazada/cerrada - Candidato', 'Notifica al candidato el descarte de la candidatura.', 'Actualización de tu candidatura: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Estimado/a $stic_job_applications_stic_job_applications_contacts_name:\n\nMuchas gracias por tu interés en la oferta de $stic_job_applications_stic_job_applications_stic_job_offers_name.\n\nTras una valoración detallada, lamentamos comunicarte que en esta ocasión hemos decidido avanzar con otras candidaturas que se ajustan más a los requisitos actuales.\n\nPuedes consultar el estado en tu área privada: $portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id\n\nTe deseamos mucho éxito. Atentamente, $stic_job_applications_interlocutor', '<p>Estimado/a <strong>$stic_job_applications_stic_job_applications_contacts_name</strong>:</p><p>Muchas gracias por el interés que has mostrado en nuestra oferta de <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong>.</p><p>Tras una valoración detallada, lamentamos comunicarte que en esta ocasión hemos decidido avanzar con otras candidaturas que se ajustan más a los requisitos actuales.</p><p>Puedes consultar el estado en tu área privada: <a href=\"$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id\">Acceder al área privada</a>.</p><p>Te deseamos mucho éxito en tus próximos retos profesionales.</p><p>Atentamente,<br><strong>$stic_job_applications_interlocutor</strong></p>', 0, '1', 0, 'notification'),
	-- Candidatura Otros estados - Usuario asignado 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0007', NOW(), NOW(), '1', '1', NULL, 'Ejemplo - Candidatura otros estados - Usuario asignado ', 'Notifica al usuario asignado cuando una candidatura pasa a otros estados, con enlace al CRM.', 'Cambio de estado de candidatura: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Estimado/a $stic_job_applications_assigned_user_name,\r\n\r\nLa candidatura de $stic_job_applications_stic_job_applications_contacts_name para la oferta $stic_job_applications_stic_job_applications_stic_job_offers_name ha cambiado a estado $stic_job_applications_status.\r\n\r\nPuede acceder en detalle:: $sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id', '<p>Estimado/a $stic_job_applications_assigned_user_name,</p><p>La candidatura de <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> para la oferta <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> ha cambiado a estado <strong>$stic_job_applications_status</strong>.</p><p>Puede acceder en detalle:: <a href="$sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id">Abrir candidatura en CRM</a>.</p>', 0, '1', 0, 'notification'),
	-- Candidatura Otros estados - Candidato 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0008', NOW(), NOW(), '1', '1', NULL, 'Ejemplo - Candidatura otros estados - Candidato ', 'Notifica al candidato cuando su candidatura pasa a otros estados, con enlace al área privada.', 'Cambio de estado de tu candidatura: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Estimado/a $stic_job_applications_stic_job_applications_contacts_name:\r\n\r\nTu candidatura para la oferta $stic_job_applications_stic_job_applications_stic_job_offers_name ha cambiado a estado $stic_job_applications_status.\r\n\r\nPuedes consultar el detalle en tu área privada: $portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id', '<p>Estimado/a $stic_job_applications_stic_job_applications_contacts_name:</p><p>Tu candidatura para la oferta <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> ha cambiado a estado <strong>$stic_job_applications_status</strong>.</p><p>Puedes consultar el detalle en tu área privada: <a href="$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id">Acceder al área privada</a>.</p>', 0, '1', 0, 'notification'),
	-- Oferta - Cambio de estado - Usuario asignado 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0010', NOW(), NOW(), '1', '1', NULL, 'Ejemplo - Oferta cambio de estado - Usuario asignado ', 'Notifica al usuario asignado cuando cambia el estado de una oferta, con enlace al CRM.', 'Cambio de estado de oferta: $stic_job_offers_name', 'Estimado/a $stic_job_offers_assigned_user_name,\r\n\r\nLa oferta $stic_job_offers_name ha cambiado a estado $stic_job_offers_status.\r\n\r\nPuede acceder en detalle:: $sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id', '<p>Estimado/a $stic_job_offers_assigned_user_name,</p><p>La oferta <strong>$stic_job_offers_name</strong> ha cambiado a estado <strong>$stic_job_offers_status</strong>.</p><p>Puede acceder en detalle:: <a href="$sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id">Abrir oferta en CRM</a>.</p>', 0, '1', 0, 'notification'),
	-- Oferta - Cambio de estado - Candidatos 
	('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0011', NOW(), NOW(), '1', '1', NULL, 'Ejemplo - Oferta cambio de estado - Candidatos ', 'Notifica a candidatos un cambio de estado de oferta, con enlace al área privada.', 'Actualización de la oferta: $stic_job_offers_name', 'Estimado/a:\r\n\r\nLa oferta $stic_job_offers_name ha cambiado de estado a $stic_job_offers_status.\r\n\r\nPuedes consultar la oferta en el área privada: $portal_address/?internalpage=single_stic_job_offers&action=detail&id=$stic_job_offers_id', '<p>Estimado/a:</p><p>La oferta <strong>$stic_job_offers_name</strong> ha cambiado de estado a <strong>$stic_job_offers_status</strong>.</p><p>Puedes consultar la oferta en el área privada: <a href="$portal_address/?internalpage=single_stic_job_offers&action=detail&id=$stic_job_offers_id">Ver oferta en área privada</a>.</p>', 0, '1', 0, 'notification'),
	-- Área Privada - Credenciales de acceso - Persona
	('6e6f5a91-2cb9-4f42-bf26-0a13b2f1c101', NOW(), NOW(), '1', '1', NULL, 'Ejemplo - Área Privada - Credenciales de acceso (Persona)', 'Plantilla inicial para enviar las credenciales del Área Privada a Personass cuando se activa el acceso', 'Tus credenciales de acceso al Área Privada', 'Hola $contacts_name,\r\n\r\nYa tienes habilitado el acceso al Área Privada.\r\n\r\nUsuario: $contacts_stic_pa_username_c\r\nContraseña: $contacts_stic_pa_password_c\r\n\r\nAccede desde: $portal_address\r\n\r\nSi no has solicitado este acceso, contacta con la entidad.', '<p>Hola $contacts_name,</p><p>Ya tienes habilitado el acceso al Área Privada.</p><p><strong>Usuario:</strong> $contacts_stic_pa_username_c<br><strong>Contraseña:</strong> $contacts_stic_pa_password_c</p><p>Accede desde: <a href="$portal_address">$portal_address</a></p><p>Si no has solicitado este acceso, contacta con la entidad.</p>', 0, '1', 0, 'notification'),
	-- Área Privada - Credenciales de acceso - Organización
	('6e6f5a91-2cb9-4f42-bf26-0a13b2f1c102', NOW(), NOW(), '1', '1', NULL, 'Ejemplo - Área Privada - Credenciales de acceso (Organización)', 'Plantilla inicial para enviar las credenciales del Área Privada a Organizaciones cuando se activa el acceso', 'Credenciales de acceso al Área Privada', 'Hola $accounts_name,\r\n\r\nYa tienes habilitado el acceso al Área Privada.\r\n\r\nUsuario: $accounts_stic_pa_username_c\r\nContraseña: $accounts_stic_pa_password_c\r\n\r\nAccede desde: $portal_address\r\n\r\nSi no has solicitado este acceso, contacta con la entidad.', '<p>Hola $accounts_name,</p><p>Ya tienes habilitado el acceso al Área Privada.</p><p><strong>Usuario:</strong> $accounts_stic_pa_username_c<br><strong>Contraseña:</strong> $accounts_stic_pa_password_c</p><p>Accede desde: <a href="$portal_address">$portal_address</a></p><p>Si no has solicitado este acceso, contacta con la entidad.</p>', 0, '1', 0, 'notification'),
	-- Candidatura - Noficación - Nueva candidatura presentada (Usuario asignado)
	('7a9f8f3a-2d1f-4a40-9dd6-7c6f9e1b7001', NOW(), NOW(), '1', '1', NULL, 'Ejemplo - Candidatura presentada - Usuario asignado', 'Notifica al usuario asignado cuando se presenta una nueva candidatura, con enlace al CRM.', 'Nueva candidatura recibida: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Estimado/a $stic_job_applications_assigned_user_name,\r\n\r\nSe ha presentado una nueva candidatura de $stic_job_applications_stic_job_applications_contacts_name para la oferta $stic_job_applications_stic_job_applications_stic_job_offers_name.\r\n\r\nPuedes revisarla en el CRM: $sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id', '<p>Estimado/a $stic_job_applications_assigned_user_name,</p><p>Se ha presentado una nueva candidatura de <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> para la oferta <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong>.</p><p>Puedes revisarla en el CRM: <a href=\"$sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id\">Abrir candidatura en CRM</a>.</p>', 0, '1', 0, 'notification'),
	-- Candidatura - Notificación - Candidatura registrada (candidato)
	('7a9f8f3a-2d1f-4a40-9dd6-7c6f9e1b7003', NOW(), NOW(), '1', '1', NULL, 'Ejemplo - Candidatura presentada - Candidato', 'Notifica al candidato que su candidatura ha quedado registrada, con enlace al área privada.', 'Hemos recibido tu candidatura: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Estimado/a $stic_job_applications_stic_job_applications_contacts_name,\r\n\r\nHemos recibido tu candidatura para la oferta $stic_job_applications_stic_job_applications_stic_job_offers_name y ha quedado registrada.\r\n\r\nPuedes consultar el detalle en tu área privada: $portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id', '<p>Estimado/a $stic_job_applications_stic_job_applications_contacts_name,</p><p>Hemos recibido tu candidatura para la oferta <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> y ha quedado registrada.</p><p>Puedes consultar el detalle en tu área privada: <a href=\"$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id\">Acceder al área privada</a>.</p>', 0, '1', 0, 'notification'),
	-- Mensaje - Notificación - Nuevo mensaje en conversación
	('7a9f8f3a-2d1f-4a40-9dd6-7c6f9e1b7002', NOW(), NOW(), '1', '1', NULL, 'Ejemplo - Nuevo mensaje en conversación - Usuario asignado', 'Notifica al usuario asignado cuando llega un nuevo mensaje en una conversación.', 'Nuevo mensaje recibido', 'Estimado/a $stic_messages_assigned_user_name,\r\n\r\nSe ha recibido un nuevo mensaje en una conversación del portal.\r\n\r\nMensaje:\r\n$stic_messages_message\r\n\r\nPuedes revisarlo en el CRM: $sugarurl/index.php?module=stic_Messages&action=DetailView&record=$stic_messages_id', '<p>Estimado/a $stic_messages_assigned_user_name,</p><p>Se ha recibido un nuevo mensaje en una conversación del portal.</p><p><strong>Mensaje:</strong><br>$stic_messages_message</p><p>Puedes revisarlo en el CRM: <a href=\"$sugarurl/index.php?module=stic_Messages&action=DetailView&record=$stic_messages_id\">Abrir mensaje en CRM</a>.</p>', 0, '1', 0, 'notification'),
	-- Ofertas laborales - Notificación - Nueva oferta laboral (usuario asignado)
	('3c0a5f6e-1111-4f8a-9a11-3b1b7c2a0101', NOW(), NOW(), '1', '1', NULL, 'Ejemplo - Nueva oferta laboral - Usuario asignado', 'Notifica al usuario asignado la creación de una nueva oferta laboral.', 'Nueva oferta creada: $stic_job_offers_name', 'Estimado/a $stic_job_offers_assigned_user_name,\r\n\r\nSe ha creado una nueva oferta laboral: $stic_job_offers_name.\r\n\r\nPuede revisarla en el CRM: $sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id', '<p>Estimado/a $stic_job_offers_assigned_user_name,</p><p>Se ha creado una nueva oferta laboral: <strong>$stic_job_offers_name</strong>.</p><p>Puede revisarla en el CRM: <a href="$sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id">Abrir oferta en CRM</a>.</p>', 0, '1', 0, 'notification');

